mapper.update:
UPDATE twin_job_schedule_config
SET last_status = 'RUNNING',
    last_run_at = #{runAt},
    last_error = NULL,
    updated_by = #{updatedBy}
WHERE job_key = #{jobKey}

UPDATE twin_job_schedule_config
SET last_status = 'FAILED',
    last_run_at = #{runAt},
    last_error = #{error},
    updated_by = #{updatedBy}
WHERE job_key = #{jobKey}
